// ===== Normalisation & Contrôle =====

// --- CONFIG ---
const CHAMPS_CONTEXTE_REQUIS = ['Client', 'Mail', 'NumeroFacture', 'MontantTTC'];

// Date d'exécution au format JJ-MM-AAAA
const dateExecution = new Date().toISOString().split('T')[0];
// Résultat : "2026-06-25"

// --- helpers ---

function nettoyer(raw) {
  if (raw == null) return '';
  let t = String(raw).trim();
  t = t.replace(/^```[a-zA-Z]*\s*/, '');
  t = t.replace(/```$/, '');
  return t.trim();
}

function lireTexte(json) {
  if (typeof json === 'string') return json;
  if (json && typeof json.text === 'string') return json.text;
  if (json && typeof json.output === 'string') return json.output;
  return '';
}

function decouper(texte) {
  const lignes = texte.split('\n');
  let objet = '';
  let debutCorps = 0;

  for (let i = 0; i < lignes.length; i++) {
    const m = lignes[i].match(/^\s*Objet\s*:\s*(.+)$/i);
    if (m) {
      objet = String(m[1]).trim(); // ✅ Correctif ici
      debutCorps = i + 1;
      break;
    }
  }
  const corps = lignes.slice(debutCorps).join('\n').trim();
  return { objet, corps };
}

// --- traitement ---
const sortie = [];

for (const item of $input.all()) {
  const f = item.json;

  const texte = nettoyer(lireTexte(f));
  const { objet, corps } = decouper(texte);

  const erreurs = [];

  if (!texte)  erreurs.push('Réponse LLM vide');
  if (!objet)  erreurs.push('Objet manquant (ligne "Objet :" absente)');
  if (!corps)  erreurs.push('Corps de l\'e-mail vide');

  for (const champ of CHAMPS_CONTEXTE_REQUIS) {
    const v = f[champ];
    if (v === undefined || v === null || String(v).trim() === '') {
      erreurs.push(`Champ contexte vide : ${champ}`);
    }
  }

  const controleOK = erreurs.length === 0;

  const mailErreur = controleOK ? null : {
    destinataire: 'interne',
    objet: `[ALERTE] Relance non envoyée – facture ${f.NumeroFacture || 'inconnue'}`,
    corps:
      `Envoi bloqué par le contrôle automatique.\n\n` +
      `Client : ${f.Client || 'N/A'}\n` +
      `Facture : ${f.NumeroFacture || 'N/A'}\n` +
      `Montant TTC : ${f.MontantTTC || 'N/A'}\n\n` +
      `Erreurs détectées :\n- ${erreurs.join('\n- ')}\n\n` +
      `Aucun e-mail n'a été adressé au client.`,
  };

  sortie.push({
    json: {
      ...f,
      objet,
      corps,
      controleOK,
      erreurs,
      envoiAutorise: controleOK,
      mailErreur,
      dateExecution,
    },
  });
}

return sortie;

