// ===== Calcul Retards & Niveau =====

// --- CONFIG (modifiable librement) ---
const JOURS_PREMIERE_RELANCE = 30;   // 1re relance : DateFacture + 30 j
const JOURS_ENTRE_RELANCES   = 10;   // suivantes : DerniereRelance + 10 j
const NIVEAU_ALERTE_INTERNE  = 4;    // à partir de ce niveau -> alerte interne
const STATUT_PAYEE           = 'Payée';
const TON_PAR_NIVEAU = { 1: 'courtois', 2: 'ferme', 3: 'mise en demeure' };

// --- helpers ---
function parseDate(v) {
  if (!v) return null;
  let d = new Date(v);                       // ISO (AAAA-MM-JJ) ou date Airtable
  if (!isNaN(d)) return d;
  const m = String(v).match(/^(\d{2})\/(\d{2})\/(\d{4})$/); // fallback JJ/MM/AAAA
  if (m) return new Date(`${m[3]}-${m[2]}-${m[1]}`);
  return null;
}
function joursEntre(d1, d2) {
  return Math.floor((d2 - d1) / (1000 * 60 * 60 * 24));
}

const aujourdhui = new Date();
const sortie = [];

for (const item of $input.all()) {
  const f = item.json;

  const dateFacture      = parseDate(f.DateFacture);
  const derniereRelance  = parseDate(f.DerniereRelance);
  const relancesEnvoyees = Number(f.RelancesEnvoyees) || 0;
  const statut           = (f.Statut || '').trim();

  const prochainNiveau = relancesEnvoyees + 1;
  const alerteInterne  = prochainNiveau >= NIVEAU_ALERTE_INTERNE;

  const joursDepuisFacture  = dateFacture ? joursEntre(dateFacture, aujourdhui) : null;
  const joursDepuisDerniere = derniereRelance ? joursEntre(derniereRelance, aujourdhui) : null;

  let doitRelancer = false;
  let raison = '';

  if (statut === STATUT_PAYEE) {
    raison = 'Facture payée';
  } else if (!dateFacture) {
    raison = 'DateFacture manquante ou illisible';
  } else if (relancesEnvoyees === 0) {
    if (joursDepuisFacture >= JOURS_PREMIERE_RELANCE) {
      doitRelancer = true;
      raison = `1re relance due (${joursDepuisFacture} j depuis facture)`;
    } else {
      raison = `Non échu (${joursDepuisFacture}/${JOURS_PREMIERE_RELANCE} j)`;
    }
  } else if (joursDepuisDerniere === null) {
    raison = 'DerniereRelance manquante alors que RelancesEnvoyees > 0';
  } else if (joursDepuisDerniere >= JOURS_ENTRE_RELANCES) {
    doitRelancer = true;
    raison = `Relance n°${prochainNiveau} due (${joursDepuisDerniere} j depuis dernière)`;
  } else {
    raison = `Délai non écoulé (${joursDepuisDerniere}/${JOURS_ENTRE_RELANCES} j)`;
  }
// Escalade manager si montant élevé (garde-fou WF2)
  const montantTTC = Number(String(f.MontantTTC).replace(/[^\d.,-]/g, '').replace(',', '.')) || 0;
  const escaladeManager = montantTTC > 30000;
  sortie.push({
    json: {
      ...f,
      joursDepuisFacture,
      joursDepuisDerniere,
      prochainNiveau,
      ton: TON_PAR_NIVEAU[prochainNiveau] || 'mise en demeure',
      alerteInterne,
      destinataire: alerteInterne ? 'interne' : 'client',
      doitRelancer,
      raison,
    },
  });
}

return sortie;
